8	type Item = { type: string };
9	type QuoteStep = { op: "quote"; items: Item[] };
10	type Step = QuoteStep;
11	type Scenario = { customer: unknown; steps: Step[] };
12	type QuoteResult = { premium: number };
13	type StepResult = QuoteResult;
14	
15	const basePremiumForItem = (item: Item): number =>
16	  BASE_PREMIUM_BY_ITEM_TYPE[item.type] ?? 0;
17	
18	const quote = (step: QuoteStep): QuoteResult => {
19	  const base = step.items.reduce((sum, item) => sum + basePremiumForItem(item), 0);
20	  return { premium: base + PROCESSING_FEE };
21	};
22	
23	export const processScenario = (input: Scenario): { results: StepResult[] } => {
24	  const results = input.steps.map((step) => quote(step));
25	  return { results };
26	};
